@workflow:name: Extraire Audio
@workflow:description: Extrait la piste audio d'un fichier video ou convertit un fichier audio en WAV 16kHz mono via ffmpeg.
@workflow:input: {
    "fichier_source":   {"type": "string",  "required": true,                        "description": "Chemin vers le fichier video ou audio source"},
    "dossier_sortie":   {"type": "string",  "default": "./output",                   "description": "Dossier de destination pour le fichier WAV"},
    "nom_sortie":       {"type": "string",  "default": "audio_brut.wav",             "description": "Nom du fichier WAV genere"},
    "frequence":        {"type": "int",     "default": 16000, "min": 8000, "max": 48000, "description": "Frequence d'echantillonnage en Hz"},
    "canaux":           {"type": "int",     "default": 1, "min": 1, "max": 2,       "description": "Nombre de canaux audio (1=mono, 2=stereo)"}
}
@workflow:output: {
    "chemin_audio":     {"type": "string",  "description": "Chemin absolu vers le fichier WAV produit"},
    "duree_secondes":   {"type": "float",   "description": "Duree du fichier audio en secondes"},
    "est_video":        {"type": "bool",    "description": "True si le fichier source etait une video"}
}
@workflow:dependencies: pydub

@workflow:name: Reduire Bruit
@workflow:description: Applique une reduction de bruit sur un fichier audio WAV via noisereduce (reduction spectrale non-stationnaire).
@workflow:input: {
    "chemin_audio":     {"type": "string",  "required": true,                        "description": "Chemin vers le fichier WAV a traiter"},
    "dossier_sortie":   {"type": "string",  "default": "./output",                   "description": "Dossier de destination"},
    "nom_sortie":       {"type": "string",  "default": "audio_denoise.wav",          "description": "Nom du fichier WAV debruite"},
    "force_reduction":  {"type": "float",   "default": 0.75,                         "description": "Intensite de la reduction (0.0 a 1.0)"},
    "stationnaire":     {"type": "bool",    "default": false,                        "description": "Utiliser le mode stationnaire (bruit constant)"}
}
@workflow:output: {
    "chemin_audio":     {"type": "string",  "description": "Chemin absolu vers le fichier WAV debruite"},
    "duree_secondes":   {"type": "float",   "description": "Duree du fichier audio en secondes"},
    "echantillons":     {"type": "int",     "description": "Nombre total d'echantillons traites"}
}
@workflow:dependencies: noisereduce,numpy,soundfile

@workflow:name: Normaliser Volume
@workflow:description: Normalise le volume d'un fichier audio WAV vers un niveau cible en dBFS via pydub.
@workflow:input: {
    "chemin_audio":     {"type": "string",  "required": true,                        "description": "Chemin vers le fichier WAV a normaliser"},
    "dossier_sortie":   {"type": "string",  "default": "./output",                   "description": "Dossier de destination"},
    "nom_sortie":       {"type": "string",  "default": "audio_normalise.wav",        "description": "Nom du fichier WAV normalise"},
    "niveau_cible":     {"type": "float",   "default": -20.0,                        "description": "Niveau cible en dBFS (-30 a 0)"}
}
@workflow:output: {
    "chemin_audio":     {"type": "string",  "description": "Chemin absolu vers le fichier WAV normalise"},
    "volume_avant":     {"type": "float",   "description": "Volume d'origine en dBFS"},
    "volume_apres":     {"type": "float",   "description": "Volume apres normalisation en dBFS"},
    "gain_applique":    {"type": "float",   "description": "Gain applique en dB"}
}
@workflow:dependencies: pydub

@workflow:name: Transcrire Audio
@workflow:description: Transcrit un fichier audio en texte via Whisper avec detection optionnelle des locuteurs par diarisation MFCC.
@workflow:input: {
    "chemin_audio":         {"type": "string",  "required": true,                            "description": "Chemin vers le fichier WAV a transcrire"},
    "taille_modele":        {"type": "list",    "options": ["tiny", "base", "small", "medium", "large"], "default": "base", "description": "Taille du modele Whisper"},
    "langue":               {"type": "list",    "options": ["auto", "fr", "en", "es", "de", "it", "pt", "nl", "ja", "zh"], "default": "auto", "description": "Langue de l'audio (auto = detection automatique)"},
    "detection_locuteurs":  {"type": "bool",    "default": true,                             "description": "Activer la detection des locuteurs (diarisation)"},
    "nombre_locuteurs":     {"type": "int",     "default": 0, "min": 0, "max": 10,          "description": "Nombre de locuteurs attendus (0 = estimation automatique)"}
}
@workflow:output: {
    "segments":             {"type": "array",   "description": "Liste des segments {start, end, text, speaker}"},
    "texte_complet":        {"type": "string",  "description": "Transcription complete concatenee"},
    "langue_detectee":      {"type": "string",  "description": "Code langue detecte par Whisper"},
    "nombre_segments":      {"type": "int",     "description": "Nombre total de segments transcrits"},
    "nombre_locuteurs":     {"type": "int",     "description": "Nombre de locuteurs identifies"}
}
@workflow:dependencies: openai-whisper,torch,numpy,soundfile,librosa,scikit-learn

@workflow:name: Detecter Diapositives
@workflow:description: Detecte les changements de diapositives dans une video par comparaison d'histogrammes HSV et capture les images.
@workflow:input: {
    "fichier_video":    {"type": "string",  "required": true,                        "description": "Chemin vers le fichier video a analyser"},
    "dossier_sortie":   {"type": "string",  "default": "./output/slides",            "description": "Dossier de destination pour les captures"},
    "seuil":            {"type": "float",   "default": 0.7,                          "description": "Seuil de correlation (0.0 a 1.0) — plus bas = plus sensible"}
}
@workflow:output: {
    "diapositives":     {"type": "array",   "description": "Liste des diapositives {timestamp, fichier}"},
    "nombre_diapos":    {"type": "int",     "description": "Nombre de diapositives detectees"},
    "duree_video":      {"type": "float",   "description": "Duree de la video en secondes"},
    "dossier_captures": {"type": "string",  "description": "Chemin absolu vers le dossier des captures"}
}
@workflow:dependencies: opencv-python

@workflow:name: Sauvegarder Resultats
@workflow:description: Genere les fichiers de sortie (SRT, TXT, JSON) a partir des segments de transcription et des diapositives detectees.
@workflow:input: {
    "segments":         {"type": "array",   "required": true,                        "description": "Liste des segments {start, end, text, speaker}"},
    "texte_complet":    {"type": "string",  "default": "",                           "description": "Texte complet de la transcription"},
    "langue_detectee":  {"type": "string",  "default": "inconnu",                    "description": "Code langue detecte"},
    "diapositives":     {"type": "array",   "default": [],                           "description": "Liste des diapositives {timestamp, fichier} (optionnel)"},
    "dossier_sortie":   {"type": "string",  "default": "./output",                   "description": "Dossier de destination des fichiers"},
    "nom_projet":       {"type": "string",  "default": "transcription",              "description": "Prefixe pour les noms de fichiers generes"},
    "formats":          {"type": "list",    "options": ["srt", "txt", "json", "tous"], "default": "tous", "description": "Formats de sortie a generer"}
}
@workflow:output: {
    "fichiers":         {"type": "array",   "description": "Liste des chemins de fichiers generes"},
    "fichier_json":     {"type": "string",  "description": "Chemin vers le fichier JSON complet"},
    "fichier_srt":      {"type": "string",  "description": "Chemin vers le fichier SRT (sous-titres)"},
    "fichier_txt":      {"type": "string",  "description": "Chemin vers le fichier TXT (texte brut)"}
}
@workflow:dependencies:
